<span class="line"><span style="color:#E1E4E8;">  db_storage_size  </span><span style="color:#F97583;">VARCHAR</span><span style="color:#E1E4E8;">(</span><span style="color:#79B8FF;">10</span><span style="color:#E1E4E8;">)  </span><span style="color:#F97583;">DEFAULT</span><span style="color:#9ECBFF;"> &#39;20Gi&#39;</span><span style="color:#E1E4E8;">,   </span><span style="color:#6A737D;">-- &#39;20Gi&#39; | &#39;50Gi&#39;  | &#39;100Gi&#39;</span></span>
